        glare: true,
        "max-glare": 0.3
      }
    };
  },
    methods: {
      gogoLetf(flage){
        if(flage==true){
          clearInterval(this.times);
          this.times='';
        }
        let endClass=this.yuluList[this.yuluList.length-1].x;
        for(let i=this.yuluList.length-1;i>0;i--){
          this.yuluList[i].x=this.yuluList[i-1].x;
        }
        this.yuluList[0].x=endClass;
      },

      gogoRight(flage){
        if(flage==true){
          clearInterval(this.times);
          this.times='';
        }
        let fistClass=this.yuluList[0].x;
        for(let i=0;i<this.yuluList.length-1;i++){
          this.yuluList[i].x=this.yuluList[i+1].x;
        }
        this.yuluList[this.yuluList.length-1].x=fistClass;
      }
  },
  mounted () {
    setInterval(()=>{
      if(this.times==''){
        console.log("启动");
        this.times=setInterval(this.gogoLetf,2000)
      }
    },1000)  
  },
}
</script>


